/**
 * Client-side search using a pre-built JSON index.
 * The index is served from /search-index.json (generated by Jekyll).
 */
(function () {
  'use strict';

  var searchInput = document.getElementById('search-input');
  var searchResults = document.getElementById('search-results');

  if (!searchInput || !searchResults) return;

  var index = null;
  var documents = [];

  // Load search index
  function loadIndex() {
    var url = (typeof siteBaseUrl !== 'undefined' ? siteBaseUrl : '') + '/search-index.json';
    fetch(url)
      .then(function (r) { return r.json(); })
      .then(function (data) {
        documents = data;
        index = buildIndex(data);
      })
      .catch(function () {
        // Silent fail - search just won't work
      });
  }

  // Simple inverted index
  function buildIndex(docs) {
    var idx = {};
    docs.forEach(function (doc, i) {
      var words = tokenize(doc.title + ' ' + (doc.content || ''));
      words.forEach(function (w) {
        if (!idx[w]) idx[w] = [];
        if (idx[w].indexOf(i) === -1) idx[w].push(i);
      });
    });
    return idx;
  }

  function tokenize(text) {
    return text.toLowerCase()
      .replace(/[^a-z0-9\s]/g, ' ')
      .split(/\s+/)
      .filter(function (w) { return w.length > 1; });
  }

  function search(query) {
    if (!index || !query) return [];
    var terms = tokenize(query);
    var scores = {};

    terms.forEach(function (term) {
      // Exact match
      Object.keys(index).forEach(function (word) {
        if (word.indexOf(term) === 0) {
          var boost = word === term ? 2 : 1;
          index[word].forEach(function (docIdx) {
            scores[docIdx] = (scores[docIdx] || 0) + boost;
          });
        }
      });
    });

    return Object.keys(scores)
      .sort(function (a, b) { return scores[b] - scores[a]; })
      .slice(0, 8)
      .map(function (i) { return documents[parseInt(i, 10)]; });
  }

  function highlight(text, query) {
    if (!text) return '';
    var words = tokenize(query);
    var result = escapeHtml(text.substring(0, 150));
    words.forEach(function (w) {
      var re = new RegExp('(' + escapeRegex(w) + ')', 'gi');
      result = result.replace(re, '<mark>$1</mark>');
    });
    return result;
  }

  function escapeHtml(str) {
    return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }

  function escapeRegex(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  function renderResults(results, query) {
    if (!results.length) {
      searchResults.innerHTML = '<div class="search-empty">No results for "' + escapeHtml(query) + '"</div>';
      searchResults.hidden = false;
      return;
    }

    var html = results.map(function (doc) {
      return '<a class="search-result-item" href="' + escapeHtml(doc.url) + '">' +
        '<div class="result-title">' + highlight(doc.title, query) + '</div>' +
        '<div class="result-section">' + escapeHtml(doc.section || '') + '</div>' +
        (doc.content ? '<div class="result-snippet">' + highlight(doc.content, query) + '…</div>' : '') +
        '</a>';
    }).join('');

    searchResults.innerHTML = html;
    searchResults.hidden = false;
  }

  var debounceTimer;
  searchInput.addEventListener('input', function () {
    clearTimeout(debounceTimer);
    var q = searchInput.value.trim();
    if (!q) {
      searchResults.hidden = true;
      return;
    }
    debounceTimer = setTimeout(function () {
      if (!index) {
        loadIndex();
        return;
      }
      renderResults(search(q), q);
    }, 200);
  });

  searchInput.addEventListener('focus', function () {
    if (searchInput.value.trim() && index) {
      renderResults(search(searchInput.value.trim()), searchInput.value.trim());
    }
    if (!index) loadIndex();
  });

  document.addEventListener('click', function (e) {
    if (!searchResults.contains(e.target) && e.target !== searchInput) {
      searchResults.hidden = true;
    }
  });

  // Keyboard navigation of results
  searchInput.addEventListener('keydown', function (e) {
    var items = searchResults.querySelectorAll('.search-result-item');
    var focused = searchResults.querySelector('.is-focused');
    var idx = Array.prototype.indexOf.call(items, focused);

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (focused) focused.classList.remove('is-focused');
      var next = items[idx + 1] || items[0];
      if (next) next.classList.add('is-focused');
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (focused) focused.classList.remove('is-focused');
      var prev = items[idx - 1] || items[items.length - 1];
      if (prev) prev.classList.add('is-focused');
    } else if (e.key === 'Enter') {
      if (focused) {
        e.preventDefault();
        window.location.href = focused.href;
      }
    }
  });

})();
